text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트 통과 시 금요일 15:00 KST를 공개 릴리스 목표로 한다."
      },
      {
        "topic": "packageName mismatch 대응",
        "decision": "packageName mismatch가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "result": "반려"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "note": "내부 스트레치 목표일 뿐이며 최종 공개 릴리스 결정은 아님"
      }
    ],
    "non_decisions": [
      {
        "topic": "README 설치 절차 검토",
        "note": "목요일까지 가능하면 검토하자는 의견은 있었으나 담당자 확정은 없었음"
      },
      {
        "topic": "릴리스 노트에 수요일 내부 스트레치 목표를 언급할지 여부",
        "note": "결론 없음"
      },
      {
        "topic": "최종 릴리스 승인 권한자",
        "note": "미확정"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로가 릴리스를 지연시킬 수 있음"
      },
      {
        "risk": "README 설치 절차가 오래되었으면 릴리스 노트가 사용자에게 오해를 줄 수 있음"
      }
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 수요일 내부 스트레치 목표를 언급해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "확정"
    },
    {
      "owner": "Doyun",
      "task": "실패 시 트리아지 노트를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "확정"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로를 확인한다.",
      "due": "민준 결과 공유 이후, 정확한 시한 미정",
      "status": "대기",
      "source_certainty": "확정"
    },
    {
      "owner": null,
      "task": "README 설치 절차를 목요일까지 가능하면 검토한다.",
      "due": "목요일 가능 시",
      "status": "미배정",
      "source_certainty": "미확정"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "Minjun의 스모크 테스트 통과 여부와 공유 결과",
      "스모크 실패 시 Doyun의 트리아지 노트 작성 여부",
      "스모크 결과 공유 이후 Hara의 tarball 경로 점검 결과",
      "README 설치 절차 검토의 담당자 지정 여부",
      "최종 릴리스 승인 권한자 확정 여부",
      "릴리스 노트에 수요일 내부 스트레치 목표를 포함할지 여부"
    ],
    "what_not_to_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구사항",
      "지정되지 않은 담당자",
      "명시되지 않은 마감 시한"
    ]
  },
  "non_invention_rules": [
    "인라인 픽스처에 없는 고객, 예산, 보안, 장애, 법무 사실을 추가하지 않는다.",
    "확정되지 않은 담당자나 승인권자를 추정하지 않는다.",
    "정확히 주어지지 않은 마감 시한을 임의로 만들지 않는다.",
    "수요일 릴리스는 내부 스트레치 목표로만 기록하고 최종 공개 릴리스 결정으로 승격하지 않는다.",
    "반려된 제안은 확정 결정처럼 서술하지 않는다."
  ]
}
